import{_ as e,c as a,o as t,ag as o}from"./chunks/framework.D4Vqf8I7.js";const d=JSON.parse('{"title":"4917: Machine Code For Kids - The Card Game","description":"","frontmatter":{},"headers":[],"relativePath":"docs/wi/games/board/4917.md","filePath":"docs/wi/games/board/4917.md","lastUpdated":1779893064000}'),l={name:"docs/wi/games/board/4917.md"};function h(i,r,p,n,s,g){return t(),a("div",null,r[0]||(r[0]=[o('<h1 id="_4917-machine-code-for-kids-the-card-game" tabindex="-1">4917: Machine Code For Kids - The Card Game <a class="header-anchor" href="#_4917-machine-code-for-kids-the-card-game" aria-label="Permalink to &quot;4917: Machine Code For Kids - The Card Game&quot;">​</a></h1><p><a href="https://punkx.org/4917/" target="_blank" rel="noreferrer">https://punkx.org/4917/</a></p><p>Это <mark>карточная игра для обучения детей чтению и написанию машинного кода</mark>, использующая простой 4-битный компьютер с очень простым набором инструкций, двумя регистрами общего назначения и всего 16 ячейками адресуемой памяти. Чтобы сразу управлять ожиданиями: это, по сути, 54 крошечные программы, на написание которых я потратил 2 <a href="https://punkx.org/4917/photos/walk1.jpg" target="_blank" rel="noreferrer">месяца</a> <a href="https://punkx.org/4917/photos/walk2.jpg" target="_blank" rel="noreferrer">работы</a>. В руководстве есть примеры игры, но в основном я просто прохожу по коду вместе с дочерью во время обеда или в автобусе.</p><h2 id="как-играть" tabindex="-1"><a href="./guide.html">КАК ИГРАТЬ</a> <a class="header-anchor" href="#как-играть" aria-label="Permalink to &quot;[КАК ИГРАТЬ](guide.html)&quot;">​</a></h2><h2 id="запустить-отладчик" tabindex="-1"><a href="./play.html">ЗАПУСТИТЬ ОТЛАДЧИК</a> <a class="header-anchor" href="#запустить-отладчик" aria-label="Permalink to &quot;[ЗАПУСТИТЬ ОТЛАДЧИК](play.html)&quot;">​</a></h2><hr><p>Карты содержат <strong><a href="./deck.html">54</a></strong> небольшие программы, иллюстрирующие различные низкоуровневые концепции, такие как:</p><ol><li>Цикл выборка-выполнение (fetch-execute cycle)</li><li>Аргументы инструкций</li><li>Переменные</li><li>Указатели</li><li>Самоизменяющиеся программы</li><li>Самоповреждающиеся программы</li><li>Код с самоссылками</li><li>Переполнения и недополнения целых чисел</li><li>Управление потоком и адресуемая память</li><li>Код — это данные</li><li>Данные — это код</li><li>Отладка</li></ol><hr><p><a href="https://punkx.org/4917/photos/a.jpg" target="_blank" rel="noreferrer"><img src="https://punkx.org/4917/photos/a.jpg" alt="A"></a><a href="https://punkx.org/4917/photos/c.jpg" target="_blank" rel="noreferrer"><img src="https://punkx.org/4917/photos/c.jpg" alt="C"></a><a href="https://punkx.org/4917/photos/d.jpg" target="_blank" rel="noreferrer"><img src="https://punkx.org/4917/photos/d.jpg" alt="D"></a></p><ul><li>распечатать на A4: <a href="./deck.html">список всех 55 карт</a>, уменьшенных до ширины 25%, чтобы их можно было напечатать на 7 листах бумаги A4 (альбомная ориентация, без полей)</li><li>код: <a href="https://github.com/jackdoe/programming-for-kids/tree/master/projects/4917/deck" target="_blank" rel="noreferrer">4917</a></li><li>автор: <a href="https://github.com/jackdoe" target="_blank" rel="noreferrer">github.com/jackdoe</a></li><li>соавтор: <a href="https://punkjazz.org/jackie" target="_blank" rel="noreferrer">Jackie</a></li><li>контакт: <a href="mailto:b0000@fastmail.com" target="_blank" rel="noreferrer">b0000@fastmail.com</a></li><li>лицензия: CC BY 4.0</li></ul><p><s><strong>Купить сейчас: €5,00 EUR</strong></s> [ распродано ]</p><hr><p>Игра основана на <a href="https://www.youtube.com/watch?v=gTeDX4yAdyU" target="_blank" rel="noreferrer">4-битном компьютере</a> Ричарда Бакленда.</p><blockquote><p><strong>Примечание:</strong> Когда вы играете с ребёнком, установите <a href="https://x64dbg.com/" target="_blank" rel="noreferrer">x64dbg</a> и покажите ему настоящий машинный код программы во время её выполнения. Также очень полезно написать небольшую программу на C, которая делает примерно то же самое, что и конкретная карта, чтобы лучше проиллюстрировать концепцию.</p></blockquote><hr><h2 id="примеры-карт-6-из-55" tabindex="-1">Примеры карт (6 из 55): <a class="header-anchor" href="#примеры-карт-6-из-55" aria-label="Permalink to &quot;Примеры карт (6 из 55):&quot;">​</a></h2><p><a href="https://punkx.org/4917/play.html#1" target="_blank" rel="noreferrer"><img src="https://punkx.org/4917/images/deck/front_card_001.jpg" alt="Card 001"></a><a href="https://punkx.org/4917/play.html#2" target="_blank" rel="noreferrer"><img src="https://punkx.org/4917/images/deck/front_card_002.jpg" alt="Card 002"></a><a href="https://punkx.org/4917/play.html#3" target="_blank" rel="noreferrer"><img src="https://punkx.org/4917/images/deck/front_card_003.jpg" alt="Card 003"></a><a href="https://punkx.org/4917/play.html#18" target="_blank" rel="noreferrer"><img src="https://punkx.org/4917/images/deck/front_card_018.jpg" alt="Card 018"></a><a href="https://punkx.org/4917/play.html#43" target="_blank" rel="noreferrer"><img src="https://punkx.org/4917/images/deck/front_card_043.jpg" alt="Card 043"></a><a href="https://punkx.org/4917/images/deck/back_card_000.jpg" target="_blank" rel="noreferrer"><img src="https://punkx.org/4917/images/deck/back_card_000.jpg" alt="Back Card"></a></p><hr><h2 id="известные-ошибки" tabindex="-1">Известные ошибки <a class="header-anchor" href="#известные-ошибки" aria-label="Permalink to &quot;Известные ошибки&quot;">​</a></h2><ul><li><strong>Карта 25:</strong> ошибка найдена пользователем <a href="https://github.com/mbkulik" target="_blank" rel="noreferrer">@mbkulik</a>, исправлена в <a href="https://github.com/jackdoe/programming-for-kids/pull/32" target="_blank" rel="noreferrer">pull/32</a>. Карта печатала <code>0,12,10,8...</code> вместо ожидаемых <code>14,12,10...</code>. В текущей печатной версии ошибка осталась на карте 25, но цифровая версия карты исправлена, если вы хотите распечатать колоду самостоятельно.</li></ul>',21)]))}const k=e(l,[["render",h]]);export{d as __pageData,k as default};
